 34→
 35→.properties {
 36→  grid-area: properties;
 37→  min-height: 0;
 38→  overflow-y: auto;
 39→}
 40→
 41→.modelWorkspace {
 42→  display: grid;
 43→  grid-template-columns: minmax(0, 1fr) minmax(300px, 28vw);
 44→  width: 100%;
 45→  height: 100%;
 46→  min-width: 0;
 47→  min-height: 0;
 48→}
 49→
 50→.primaryCanvas {
 51→  min-width: 0;
 52→  min-height: 0;
 53→}
 54→
 55→.preview {
 56→  display: flex;
 57→  min-width: 0;
 58→  min-height: 0;
 59→  height: 100%;
 60→  overflow: hidden;
 61→}
 62→
 63→.previewFallback {
 64→  display: flex;
 65→  align-items: center;
 66→  justify-content: center;
 67→  width: 100%;
 68→  height: 100%;
 69→  min-height: 0;
 70→  border-left: 1px solid var(--color-border);
 71→  background: var(--color-panel-bg);
 72→  color: var(--color-text-secondary);
 73→  font-size: 12px;
 74→  font-weight: 600;
 75→  letter-spacing: 0.04em;
 76→  text-transform: uppercase;
 77→  position: relative;
 78→  overflow: hidden;
 79→}
 80→
 81→.previewFallback::after {
 82→  content: '';
 83→  position: absolute;
 84→  inset: 0;
 85→  background: linear-gradient(90deg, transparent, rgba(255, 255, 255, 0.4), transparent);
 86→  animation: shimmer 1.5s infinite;
 87→}
 88→
 89→@keyframes shimmer {
 90→  0% { transform: translateX(-100%); }
 91→  100% { transform: translateX(100%); }
 92→}
 93→
 94→.panelHidden {
 95→  width: 0;
 96→  overflow: hidden;
 97→  padding: 0;
 98→  border: none;
 99→  transition: width var(--duration-layout) var(--ease-in-out-soft),
100→              padding var(--duration-layout) var(--ease-in-out-soft);
101→}
102→
103→.workspaceMaximized {
104→  grid-template-columns: 1fr;
105→}
106→
107→.previewHidden {
108→  display: none;
109→}
110→
111→.primaryCanvasHidden {
112→  display: none;
113→}
114→
115→@media (max-width: 1200px) {
116→  .modelWorkspace {
117→    grid-template-columns: minmax(0, 1fr);
118→    grid-template-rows: minmax(0, 1fr) 280px;
119→  }
120→
121→  .previewFallback {
122→    border-left: none;
123→    border-top: 1px solid var(--color-border);
124→  }
125→}
126→
127→@media (max-width: 1024px) {
128→  .layout {
129→    grid-template-columns: 0px 1fr 0px;
130→  }
131→  .sidebar, .properties {
132→    position: fixed;
133→    top: var(--toolbar-height);
134→    bottom: 0;
135→    z-index: 20;
136→    transition: transform var(--duration-layout) var(--ease-out);
137→    box-shadow: var(--shadow-floating);
138→    width: var(--sidebar-width);
139→    background: var(--color-panel-bg);
140→  }
141→  .sidebar {
142→    left: 0;
143→    transform: translateX(-100%);
144→  }
145→  .properties {
146→    right: 0;
147→    left: auto;
148→    width: var(--properties-width);
149→    transform: translateX(100%);
150→  }
151→  .sidebarVisible {
152→    transform: translateX(0);
153→  }
154→  .propertiesVisible {
155→    transform: translateX(0);
156→  }
157→  .panelHidden {
158→    width: auto;
159→  }
160→}
