:root {
  /* Blueprint colors (canvas stays light) */
  --color-background: #FAFAF8;
  --color-wall-fill: #2D3444;
  --color-wall-stroke: #1E2433;
  --color-grid-minor: #E6E4DE;
  --color-grid-major: #D0CDC5;
  --color-selection: #10B981;
  --color-selection-fill: rgba(16, 185, 129, 0.08);

  /* UI colors — light chrome panels */
  --color-text-primary: #1E2433;
  --color-text-secondary: #5B6275;
  --color-text-tertiary: #6E7280;
  --color-panel-bg: #F4F3F0;
  --color-panel-bg-alt: #EAEAE7;
  --color-surface-elevated: #FFFFFF;
  --color-border: rgba(0, 0, 0, 0.08);
